package com.rehealth.genie.chat

import com.google.gson.Gson
import com.google.gson.JsonParser
import java.io.BufferedReader
import java.io.OutputStreamWriter
import java.net.HttpURLConnection
import java.net.URI
import java.net.URL
import java.nio.charset.StandardCharsets

data class LunaChatConfig(
    val baseUrl: String,
    val model: String,
    val enabled: Boolean,
    val allowCleartext: Boolean,
) {
    val validationError: String?
        get() = when {
            !enabled -> "本机 AI 未启用"
            baseUrl.isBlank() -> "未配置本机 AI 地址"
            model.isBlank() -> "未配置本机 AI 模型"
            else -> validateEndpoint(baseUrl, allowCleartext)
        }

    val endpointLabel: String
        get() = runCatching {
            URI(baseUrl).let { uri ->
                if (uri.port == -1) uri.host.orEmpty() else "${uri.host}:${uri.port}"
            }
        }.getOrDefault("未配置")

    fun chatCompletionsUrl(): String = baseUrl.trimEnd('/').let {
        if (it.endsWith("/chat/completions")) it else "$it/chat/completions"
    }

    private fun validateEndpoint(value: String, allowCleartext: Boolean): String? = runCatching {
        URI(value).also { uri ->
            require(uri.scheme == "https" || uri.scheme == "http") { "本机 AI 地址必须使用 http 或 https" }
            require(!uri.host.isNullOrBlank()) { "本机 AI 地址缺少主机名" }
            require(uri.scheme != "http" || allowCleartext) { "本机 HTTP 服务需显式允许明文连接" }
        }
    }.exceptionOrNull()?.message
}

data class LunaChatMessage(val role: String, val content: String)

class LunaChatClient(
    private val config: LunaChatConfig,
    private val gson: Gson = Gson(),
) {
    fun reply(history: List<LunaChatMessage>): Result<String> = runCatching {
        config.validationError?.let { throw LunaChatException(it) }
        val connection = (URL(config.chatCompletionsUrl()).openConnection() as HttpURLConnection).apply {
            requestMethod = "POST"
            connectTimeout = CONNECT_TIMEOUT_MILLIS
            readTimeout = READ_TIMEOUT_MILLIS
            doOutput = true
            setRequestProperty("Content-Type", "application/json; charset=utf-8")
            setRequestProperty("Accept", "application/json")
        }
        try {
            val payload = ChatCompletionsRequest(model = config.model, messages = history)
            OutputStreamWriter(connection.outputStream, StandardCharsets.UTF_8).use { writer ->
                writer.write(gson.toJson(payload))
            }
            if (connection.responseCode !in 200..299) {
                throw LunaChatException("本机 AI 服务未接受请求（HTTP ${connection.responseCode}）")
            }
            val response = connection.inputStream.bufferedReader(StandardCharsets.UTF_8).use(BufferedReader::readText)
            parseAssistantReply(response)
        } catch (exception: LunaChatException) {
            throw exception
        } catch (exception: Exception) {
            throw LunaChatException("无法连接本机 AI 服务，请确认地址与服务状态", exception)
        } finally {
            connection.disconnect()
        }
    }

    internal fun parseAssistantReply(response: String): String {
        val content = JsonParser.parseString(response)
            .asJsonObject
            .getAsJsonArray("choices")
            ?.firstOrNull()
            ?.asJsonObject
            ?.getAsJsonObject("message")
            ?.get("content")
            ?.takeIf { it.isJsonPrimitive }
            ?.asString
            ?.trim()
            .orEmpty()
        if (content.isBlank()) throw LunaChatException("本机 AI 服务未返回可显示的回答")
        return content
    }

    private data class ChatCompletionsRequest(
        val model: String,
        val messages: List<LunaChatMessage>,
        val temperature: Double = 0.3,
    )

    private companion object {
        const val CONNECT_TIMEOUT_MILLIS = 10_000
        const val READ_TIMEOUT_MILLIS = 30_000
    }
}

class LunaChatException(message: String, cause: Throwable? = null) : RuntimeException(message, cause)

package com.rehealth.genie.chat

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.rehealth.genie.BuildConfig
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

data class LunaChatUiState(
    val messages: List<LunaChatMessage> = emptyList(),
    val isSending: Boolean = false,
    val errorMessage: String? = null,
    val connectionLabel: String = "本机 AI 未配置",
)

class LunaChatViewModel(
    private val config: LunaChatConfig = LunaChatConfig(
        baseUrl = BuildConfig.LUNA_API_BASE_URL,
        model = BuildConfig.LUNA_MODEL,
        enabled = BuildConfig.LUNA_API_ENABLED,
        allowCleartext = BuildConfig.LUNA_API_ENABLED && BuildConfig.LUNA_API_BASE_URL.startsWith("http://") &&
            BuildConfig.LUNA_API_BASE_URL.isNotBlank(),
    ),
    private val client: LunaChatClient = LunaChatClient(config),
) : ViewModel() {
    private val systemMessage = LunaChatMessage(
        role = "system",
        content = "你是小禾灵，健康管理助手。用中文简洁回答，提供保守的健康教育与生活方式建议，不诊断、不替代医生；紧急症状应建议立即就医。不要声称看到用户未主动提供的健康数据。",
    )
    private val mutableState = MutableStateFlow(
        LunaChatUiState(connectionLabel = initialConnectionLabel(config)),
    )
    val state: StateFlow<LunaChatUiState> = mutableState.asStateFlow()

    fun send(message: String) {
        if (message.isBlank() || mutableState.value.isSending) return
        val userMessage = LunaChatMessage(role = "user", content = message.trim())
        mutableState.update {
            it.copy(messages = (it.messages + userMessage).takeLast(MAX_VISIBLE_MESSAGES), isSending = true, errorMessage = null)
        }
        viewModelScope.launch {
            val visibleMessages = mutableState.value.messages
            val result = withContext(Dispatchers.IO) { client.reply(listOf(systemMessage) + visibleMessages) }
            result.fold(
                onSuccess = { reply ->
                    mutableState.update {
                        it.copy(
                            messages = (it.messages + LunaChatMessage("assistant", reply)).takeLast(MAX_VISIBLE_MESSAGES),
                            isSending = false,
                            connectionLabel = "本机 AI 已连接：${config.endpointLabel}",
                        )
                    }
                },
                onFailure = { error ->
                    mutableState.update {
                        it.copy(
                            isSending = false,
                            errorMessage = error.message ?: "本机 AI 服务请求失败",
                            connectionLabel = "本机 AI 不可达：${config.endpointLabel}",
                        )
                    }
                },
            )
        }
    }

    private companion object {
        const val MAX_VISIBLE_MESSAGES = 12

        fun initialConnectionLabel(config: LunaChatConfig): String = config.validationError?.let {
            "本机 AI：$it"
        } ?: "本机 AI 已配置：${config.endpointLabel}"
    }
}

