+private fun List<Double>.toChartPoints(): List<Float> {
+    if (size < 2) return emptyList()
+    val minimum = minOrNull() ?: return emptyList()
+    val maximum = maxOrNull() ?: return emptyList()
+    if (maximum == minimum) return List(size) { 0.5f }
+    return map { ((it - minimum) / (maximum - minimum)).toFloat().coerceIn(0.1f, 0.9f) }
