data class LunaChatConfig(
    val baseUrl: String,
    val model: String,
    val enabled: Boolean,
    val allowCleartext: Boolean,
) {
    val validationError: String?
        get() = when {
            !enabled -> "鏈満 AI 鏈惎鐢?
            baseUrl.isBlank() -> "鏈厤缃湰鏈?AI 鍦板潃"
            model.isBlank() -> "鏈厤缃湰鏈?AI 妯″瀷"
            else -> validateEndpoint(baseUrl, allowCleartext)
        }

    val endpointLabel: String
        get() = runCatching {
            URI(baseUrl).let { uri ->
                if (uri.port == -1) uri.host.orEmpty() else "${uri.host}:${uri.port}"
            }
        }.getOrDefault("鏈厤缃?)

    fun chatCompletionsUrl(): String = baseUrl.trimEnd('/').let {
        if (it.endsWith("/chat/completions")) it else "$it/chat/completions"
    }

    private fun validateEndpoint(value: String, allowCleartext: Boolean): String? = runCatching {
        URI(value).also { uri ->
            require(uri.scheme == "https" || uri.scheme == "http") { "鏈満 AI 鍦板潃蹇呴』浣跨敤 http 鎴?https" }
            require(!uri.host.isNullOrBlank()) { "鏈満 AI 鍦板潃缂哄皯涓绘満鍚? }
            require(uri.scheme != "http" || allowCleartext) { "鏈満 HTTP 鏈嶅姟闇€鏄惧紡鍏佽鏄庢枃杩炴帴" }
        }
    }.exceptionOrNull()?.message
}

data class LunaChatMessage(val role: String, val content: String)

class LunaChatClient(
    private val config: LunaChatConfig,
    private val gson: Gson = Gson(),
) {
    fun reply(history: List<LunaChatMessage>): Result<String> = runCatching {
        config.validationError?.let { throw LunaChatException(it) }
        val connection = (URL(config.chatCompletionsUrl()).openConnection() as HttpURLConnection).apply {
            requestMethod = "POST"
            connectTimeout = CONNECT_TIMEOUT_MILLIS
            readTimeout = READ_TIMEOUT_MILLIS
            doOutput = true
            setRequestProperty("Content-Type", "application/json; charset=utf-8")
            setRequestProperty("Accept", "application/json")
        }
        try {
            val payload = ChatCompletionsRequest(model = config.model, messages = history)
            OutputStreamWriter(connection.outputStream, StandardCharsets.UTF_8).use { writer ->
                writer.write(gson.toJson(payload))
            }
            if (connection.responseCode !in 200..299) {
                throw LunaChatException("鏈満 AI 鏈嶅姟鏈帴鍙楄姹傦紙HTTP ${connection.responseCode}锛?)
            }
            val response = connection.inputStream.bufferedReader(StandardCharsets.UTF_8).use(BufferedReader::readText)
            parseAssistantReply(response)
        } catch (exception: LunaChatException) {
            throw exception
        } catch (exception: Exception) {
            throw LunaChatException("鏃犳硶杩炴帴鏈満 AI 鏈嶅姟锛岃纭鍦板潃涓庢湇鍔＄姸鎬?, exception)
        } finally {
            connection.disconnect()
        }
    }

    internal fun parseAssistantReply(response: String): String {
        val content = JsonParser.parseString(response)
            .asJsonObject
            .getAsJsonArray("choices")
            ?.firstOrNull()
            ?.asJsonObject
            ?.getAsJsonObject("message")
            ?.get("content")
            ?.takeIf { it.isJsonPrimitive }
            ?.asString
            ?.trim()
            .orEmpty()
        if (content.isBlank()) throw LunaChatException("鏈満 AI 鏈嶅姟鏈繑鍥炲彲鏄剧ず鐨勫洖绛?)
        return content
    }

    private data class ChatCompletionsRequest(
        val model: String,
        val messages: List<LunaChatMessage>,
        val temperature: Double = 0.3,
    )

    private companion object {
        const val CONNECT_TIMEOUT_MILLIS = 10_000
        const val READ_TIMEOUT_MILLIS = 30_000
    }
}

class LunaChatException(message: String, cause: Throwable? = null) : RuntimeException(message, cause)

package com.rehealth.genie.chat

import org.junit.Assert.assertEquals
import org.junit.Assert.assertNull
import org.junit.Assert.assertTrue
import org.junit.Test

class LunaChatClientTest {
    @Test
    fun `configured https endpoint creates chat completions path`() {
        val config = LunaChatConfig(
            baseUrl = "https://ai.example.test/v1",
            model = "gpt-5.6-luna",
            enabled = true,
            allowCleartext = false,
        )

        assertNull(config.validationError)
        assertEquals("https://ai.example.test/v1/chat/completions", config.chatCompletionsUrl())
        assertEquals("ai.example.test", config.endpointLabel)
    }

    @Test
    fun `http endpoint needs explicit cleartext opt in`() {
        val config = LunaChatConfig(
            baseUrl = "http://192.168.1.6:8000/v1",
            model = "gpt-5.6-luna",
            enabled = true,
            allowCleartext = false,
        )

        assertTrue(config.validationError.orEmpty().contains("鏄惧紡鍏佽鏄庢枃"))
    }

    @Test
    fun `parses OpenAI compatible assistant content`() {
        val client = LunaChatClient(
            LunaChatConfig("https://ai.example.test/v1", "gpt-5.6-luna", true, false),
        )

        assertEquals("鎮ㄥソ", client.parseAssistantReply("{\"choices\":[{\"message\":{\"content\":\" 鎮ㄥソ \"}}]}"))
    }
}

